    public class JwtAuthenticationMiddleware
    {
        private readonly RequestDelegate _next;
        private readonly JwtSettings _jwtSettings;

        public JwtAuthenticationMiddleware(RequestDelegate next, JwtSettings jwtSettings)
        {
